function detectQueryLanguage(q){
 const s=String(q||"").toLowerCase();
 if(/[\u0D00-\u0D7F]/u.test(s))return "ml";
 if(/[\u0C80-\u0CFF]/u.test(s))return "kn";
 if(/[\u0C00-\u0C7F]/u.test(s))return "te";
 if(/[\u0B80-\u0BFF]/u.test(s))return "ta";
 if(/[\u0A80-\u0AFF]/u.test(s))return "gu";
 if(/[\u0A00-\u0A7F]/u.test(s))return "pa";
 if(/[\u0980-\u09FF]/u.test(s))return "bn";
 if(/[\u0600-\u06FF]/u.test(s))return /[ٹڈڑںےھ]|کیا|چاہیے|کتنا|رابطہ/u.test(s)?"ur":"ar";
 if(/[\u0400-\u04FF]/u.test(s))return "ru";
 if(/[\u3040-\u30FF]/u.test(s))return "ja";
 if(/[\uAC00-\uD7AF]/u.test(s))return "ko";
 if(/[\u4E00-\u9FFF]/u.test(s))return "zh";
 if(/[\u0900-\u097F]/u.test(s))return /आहे|काय|किंमत|वेळ|पाहिजे|तुम्ही|करता/u.test(s)?"mr":"hi";
 const latin=[
  ["es",/\b(hola|servicios|precio|costo|cuánto|quiero|sitio web|plazo)\b/u],
  ["fr",/\b(bonjour|prix|coût|combien|développer|délai|devis|que proposez|que faites)\b/u],
  ["de",/\b(hallo|dienstleistungen|preis|kosten|entwickeln|dauer|dauert|angebot|wie lange|was bieten|was machen)\b/u],
  ["pt",/\b(olá|serviços|preço|custo|quanto|desenvolver|prazo)\b/u]
 ];
 for(const [lang,re] of latin)if(re.test(s))return lang;
 return null;
}
function multilingualKnowledgeAnswer(q){
 const lang=detectQueryLanguage(q),pack=lang&&MULTILINGUAL_PACKS[lang],terms=lang&&MULTILINGUAL_TERMS[lang];
 if(!pack||!terms)return null;
 const s=String(q||"").toLowerCase();
 const has=key=>terms[key].some(term=>s.includes(term));
 if(has("contact"))return pack.contact;
 if(has("price"))return pack.price;
 if(has("timeline"))return pack.timeline;
 if(has("process"))return pack.process;
 if(has("build"))return pack.build;
 if(has("services"))return pack.services;
 return null;
}

