function inScope(q,previous=''){if(multilingualKnowledgeAnswer(q)||isBuildEnquiry(q,previous)||priorityAnswer(q,previous)||faqMatch(q)||isGreeting(q))return true;const raw=(q+' '+previous).toLowerCase(),s=' '+canonicalize(q)+' ';return SCOPE_ROOTS.some(root=>s.includes(root))||MULTILINGUAL_SCOPE.some(root=>raw.includes(root))}
function localAnswer(q,previous=''){const multilingual=multilingualKnowledgeAnswer(q);if(multilingual)return multilingual;if(isGreeting(q))return isRomanHinglish(q)?'Hello! Main TTRL Work AI hoon. Aap website, software, AI, automation, Excel, Power BI, project process, pricing ya contact ke baare mein pooch sakte hain.':'Hello! I am TTRL Work AI. Ask me about Mosin Shaikh, websites, software, AI, automation, Excel, Power BI, projects, process, pricing or contact details.';const priority=priorityAnswer(q,previous);if(priority)return priority;if(isBuildEnquiry(q,previous))return buildEnquiryAnswer(q,previous);if(websiteBuildIntent(q))return websiteBuildAnswer(q);const match=faqMatch(q);if(match)return match.answer;if(!inScope(q,previous))return 'I can only answer questions related to Mosin Shaikh, TTRL work, projects, professional services and technology.';return 'Your question is within technology, but this device is currently using the lightweight knowledge mode. Ask a more specific question about websites, AI, automation, Excel, Power BI, software architecture, projects, process, pricing or contact—or enable On‑Device AI on a compatible WebGPU device.'}

const fab=document.querySelector('.aiFab'),panel=document.querySelector('.aiPanel'),closeAI=document.querySelector('.aiClose'),form=document.querySelector('.aiForm'),input=document.querySelector('#aiInput'),messages=document.querySelector('.aiMessages'),suggestions=document.querySelector('.aiSuggestions'),enable=document.querySelector('.enableAI'),status=document.querySelector('.aiStatus'),progress=document.querySelector('.aiProgress');
let engine=null,aiReady=false,loading=false,previousQuery='',lastBot='';const conversation=[];
try{if(enable&&localStorage.getItem('ttrlLocalAiUnsupported')==='1'){enable.textContent='Local AI unavailable';enable.disabled=true;enable.title='Knowledge Mode is active on this device'}}catch{}
function setAiState(state='idle'){const states=['is-thinking','is-ready','is-error'];states.forEach(x=>{fab?.classList.remove(x);panel?.classList.remove(x)});if(state!=='idle'){fab?.classList.add('is-'+state);panel?.classList.add('is-'+state)}}
function syncAiViewport(){if(!panel)return;const mobile=matchMedia('(max-width:520px)').matches;if(!mobile){panel.style.removeProperty('top');panel.style.removeProperty('height');panel.style.removeProperty('bottom');return}const viewport=window.visualViewport;const height=viewport?.height||innerHeight;const top=viewport?.offsetTop||0;panel.style.top=(top+8)+'px';panel.style.height=Math.max(280,height-16)+'px';panel.style.bottom='auto'}
function openPanel(){panel.inert=false;panel.classList.add('open');document.body.classList.add('ai-open');panel.setAttribute('aria-hidden','false');syncAiViewport();setTimeout(()=>{input.focus({preventScroll:true});syncAiViewport()},100)}
function closePanel(){panel.classList.remove('open');document.body.classList.remove('ai-open');panel.setAttribute('aria-hidden','true');panel.inert=true;panel.style.removeProperty('top');panel.style.removeProperty('height');panel.style.removeProperty('bottom');fab?.focus()}
function addMessage(text,who='bot',extra=''){const d=document.createElement('div');d.className='aiMsg '+who+(extra?' '+extra:'');d.textContent=text;messages.appendChild(d);requestAnimationFrame(()=>{if(who==='bot'&&!extra){const top=Math.max(0,messages.scrollTop+d.getBoundingClientRect().top-messages.getBoundingClientRect().top-8);messages.scrollTo({top,behavior:'smooth'})}else messages.scrollTop=messages.scrollHeight});return d}
async function ask(q){addMessage(q,'user');input.value='';panel.classList.add('engaged');suggestions?.setAttribute('aria-hidden','true');if(!inScope(q,previousQuery)){const refusal='I can only answer questions related to Mosin Shaikh, TTRL work, projects, professional services and technology.';addMessage(refusal);lastBot=refusal;previousQuery=q;return}conversation.push({role:'user',content:q});if(!aiReady){let answer=localAnswer(q,previousQuery);if(answer===lastBot)answer+=' To make this more specific, share the project type, required features and intended users.';addMessage(answer);conversation.push({role:'assistant',content:answer});lastBot=answer;previousQuery=q;return}setAiState('thinking');const wait=addMessage('Thinking locally on your device…','bot','thinking');try{const reply=await engine.chat.completions.create({messages:[{role:'system',content:WORK_CONTEXT+'\nCURRENT RESPONSE INSTRUCTION: Reply in the same language and script as the user\'s latest message. Use the conversation only for context; use WORK_CONTEXT as the source of truth.'},...conversation.slice(-8)],temperature:.25,max_tokens:420});wait.remove();const answer=reply.choices[0].message.content.trim();addMessage(answer);conversation.push({role:'assistant',content:answer});lastBot=answer;previousQuery=q;setAiState('ready')}catch(e){wait.remove();const answer='The local AI could not complete that response. Knowledge mode is still available. '+localAnswer(q,previousQuery);addMessage(answer);lastBot=answer;previousQuery=q;setAiState('error')}}
window.visualViewport?.addEventListener('resize',()=>{if(panel?.classList.contains('open'))syncAiViewport()});window.visualViewport?.addEventListener('scroll',()=>{if(panel?.classList.contains('open'))syncAiViewport()});addEventListener('orientationchange',()=>setTimeout(syncAiViewport,120));input?.addEventListener('focus',()=>setTimeout(syncAiViewport,80));
fab?.addEventListener('click',openPanel);closeAI?.addEventListener('click',closePanel);addEventListener('keydown',e=>{if(e.key==='Escape'&&panel?.classList.contains('open'))closePanel()});form?.addEventListener('submit',e=>{e.preventDefault();const q=input.value.trim();if(q)ask(q)});suggestions?.addEventListener('click',e=>{if(e.target.tagName==='BUTTON')ask(e.target.textContent)});
enable?.addEventListener('click',async()=>{if(aiReady||loading)return;if(!('gpu'in navigator)){try{localStorage.setItem('ttrlLocalAiUnsupported','1')}catch{}enable.textContent='Local AI unavailable';enable.disabled=true;addMessage('This device does not support the optional local model. TTRL Knowledge Mode remains active.');return}loading=true;setAiState('thinking');enable.disabled=true;progress.hidden=false;addMessage('Optional on-device AI setup started. Knowledge mode remains available if this device cannot load the local model.');try{const webllm=await import('https://cdn.jsdelivr.net/npm/@mlc-ai/web-llm@0.2.84/+esm');engine=await webllm.CreateMLCEngine('Qwen2.5-0.5B-Instruct-q4f16_1-MLC',{initProgressCallback:p=>{const n=Math.max(0,Math.min(100,Math.round((p.progress||0)*100)));progress.querySelector('span').style.width=n+'%';progress.querySelector('small').textContent=p.text||('Preparing local AI… '+n+'%')}});aiReady=true;setAiState('ready');const indicator=document.createElement('i');status.replaceChildren(indicator,document.createTextNode('On-device AI ready'));enable.textContent='AI enabled';progress.hidden=true;addMessage('On-device AI is ready. It runs in this browser without an API. Ask any work or technology question.')}catch(e){progress.hidden=true;try{localStorage.setItem('ttrlLocalAiUnsupported','1')}catch{}enable.textContent='Local AI unavailable';enable.disabled=true;addMessage('This device could not load the optional local model. No problem—TTRL Knowledge Mode is active and can still answer work, service, process, pricing and project questions.');setAiState('error');console.error(e)}finally{loading=false}});
